export const LOGO_SRC   = 'data:image/png;base64,';
export const SHEIKH_SRC = 'data:image/jpeg;base64,';

// ──────────────────────────────────────────────────
// HEADER  —  3 states: guest / student / supervisor
// ──────────────────────────────────────────────────
export function renderHeader(activePage = '', userData = null) {
  const isLoggedIn = !!userData;
  const isAdmin    = userData && (userData.role === 'superAdmin' || userData.role === 'supervisor');

  /* ── GUEST nav ── */
  const guestNav = [
    { href: 'index.html',      label: 'الرئيسية' },
    { href: 'curriculum.html', label: 'المنهج' },
    { href: 'about.html',      label: 'من نحن' },
  ];

  /* ── STUDENT nav ── */
  const studentNav = [
    { href: 'dashboard.html',  label: 'الرئيسية' },
    { href: 'courses.html',    label: 'المقررات' },
    { href: 'schedule.html',   label: 'الجدول' },
    { href: 'questions.html',  label: 'الأسئلة' },
    { href: 'curriculum.html', label: 'المنهج' },
  ];

  /* ── SUPERVISOR nav ── */
  const supervisorNav = [
    { href: 'dashboard.html',  label: 'الرئيسية' },
    { href: 'courses.html',    label: 'المقررات' },
    { href: 'schedule.html',   label: 'الجدول' },
    { href: 'questions.html',  label: 'الأسئلة' },
    { href: 'admin.html',      label: '🛠️ الإدارة', special: true },
    { href: 'curriculum.html', label: 'المنهج' },
  ];

  const navPages = isLoggedIn ? (isAdmin ? supervisorNav : studentNav) : guestNav;

  const navLinks = navPages.map(p => {
    const isActive = activePage === p.href;
    const cls = 'nav-link' + (isActive ? ' active' : '') + (p.special ? ' nav-admin-link' : '');
    return `<a href="${p.href}" class="${cls}">${p.label}</a>`;
  }).join('');

  const mobileLinks = navPages.map(p => {
    const isActive = activePage === p.href;
    const cls = 'nav-link' + (isActive ? ' active' : '') + (p.special ? ' nav-admin-link' : '');
    return `<a href="${p.href}" class="${cls}">${p.label}</a>`;
  }).join('');

  /* ── Right side — على الجوال: نخفي كل شيء إلا زر الـ hamburger ── */
  const rightSide = isLoggedIn ? `
    <div class="header-controls">
      <button class="notif-bell" id="notifBell" onclick="toggleNotifPanel()" title="الإشعارات" aria-label="الإشعارات" style="display:none;">
        🔔<span class="notif-count" id="notifCount" style="display:none;">0</span>
      </button>
      <div class="user-menu-wrap" id="userMenuWrap">
        <button class="user-menu-btn" id="userMenuBtn" onclick="toggleUserMenu()" aria-haspopup="true">
          <div class="user-avatar-mini">${userData.fullName ? userData.fullName.charAt(0) : '؟'}</div>
          <span class="user-menu-name" id="headerUserName">${userData.fullName || ''}</span>
          <span class="user-menu-arrow">▾</span>
        </button>
        <div class="user-dropdown" id="userDropdown" style="display:none;" role="menu">
          <a href="profile.html" class="user-dropdown-item">👤 ملفي الشخصي</a>
          ${isAdmin ? '<a href="admin.html" class="user-dropdown-item">🛠️ لوحة الإدارة</a>' : ''}
          <div class="user-dropdown-divider"></div>
          <button class="user-dropdown-item danger" onclick="handleHeaderLogout()">🚪 تسجيل الخروج</button>
        </div>
      </div>
      <button class="hamburger" id="hamburger" aria-label="القائمة">
        <span></span><span></span><span></span>
      </button>
    </div>` : `
    <div class="header-controls">
      <a href="register.html" class="nav-link nav-btn">تسجيل الدخول</a>
      <button class="hamburger" id="hamburger" aria-label="القائمة">
        <span></span><span></span><span></span>
      </button>
    </div>`;

  return `
  <header class="site-header" id="siteHeader">
    <div class="header-inner">
      <a href="${isLoggedIn ? 'dashboard.html' : 'index.html'}" class="logo-area">
        <img src="${LOGO_SRC}" alt="شعار معهد التأصيل العلمي" class="logo-img">
        <span class="site-name">معهد التأصيل العلمي</span>
      </a>
      <nav class="main-nav" id="mainNav">
        ${navLinks}
      </nav>
      ${rightSide}
    </div>

    <!-- ══ MOBILE MENU — يظهر عند الضغط على ☰ ══ -->
    <div class="mobile-menu" id="mobileMenu">

      ${isLoggedIn ? `
      <!-- بيانات المستخدم في أعلى القائمة -->
      <div class="mobile-menu-user">
        <div class="mob-avatar">${userData.fullName ? userData.fullName.charAt(0) : '؟'}</div>
        <div class="mob-info">
          <div class="mob-name">${userData.fullName || 'مستخدم'}</div>
          <div class="mob-role">${isAdmin ? 'مشرف' : 'طالب'}</div>
        </div>
        <button onclick="toggleNotifPanel()" title="الإشعارات"
          style="background:rgba(255,255,255,0.1);border:none;border-radius:50%;width:38px;height:38px;color:white;font-size:1.1rem;cursor:pointer;flex-shrink:0;position:relative;">
          🔔
          <span id="notifBadgeMob" style="display:none;position:absolute;top:2px;right:2px;background:#e07000;color:white;border-radius:50%;width:16px;height:16px;font-size:0.6rem;display:flex;align-items:center;justify-content:center;"></span>
        </button>
      </div>` : ''}

      <!-- روابط التنقل -->
      ${mobileLinks}

      ${isLoggedIn ? `
      <div class="mobile-menu-divider"></div>
      <a href="profile.html" class="nav-link" style="color:rgba(255,255,255,0.7);">👤 ملفي الشخصي</a>
      ${isAdmin ? '<a href="admin.html" class="nav-link nav-admin-link">🛠️ لوحة الإدارة</a>' : ''}
      <button class="mob-logout" onclick="handleHeaderLogout()">🚪 تسجيل الخروج</button>
      ` : ''}

    </div>

    <!-- Notification Panel -->
    <div class="notif-panel" id="notifPanel" style="display:none;">
      <div class="notif-header">
        <span>الإشعارات</span>
        <button onclick="markAllRead()" style="font-size:0.75rem;background:none;border:none;color:var(--gold);cursor:pointer;">تحديد الكل كمقروء</button>
      </div>
      <div class="notif-list" id="notifList">
        <div style="text-align:center;padding:24px;color:rgba(255,255,255,0.5);font-size:0.85rem;">لا توجد إشعارات</div>
      </div>
    </div>
  </header>`;
}

// ──────────────────────────────────────────────────
// FOOTER — dynamic contact info
// ──────────────────────────────────────────────────
export function renderFooter(contactData = null) {
  const phone    = contactData?.phone    || '+966 5000000000';
  const email    = contactData?.email    || 'info@taseel.com';
  const telegram = contactData?.telegram || 'https://t.me/ibnsalah';
  const channels = contactData?.channels || [];

  const channelLinks = channels.length
    ? channels.map(ch => `<a href="${ch.url}" target="_blank"><span>${ch.icon||'⛓️‍💥'}</span><span>${ch.name}</span></a>`).join('')
    : `<a href="${telegram}" target="_blank"><span class="icon">👤</span><span>قناة الشيخ مصعب بن صلاح</span></a>`;

  return `
  <footer class="site-footer">
    <div class="footer-inner">
      <div class="footer-brand">
        <img src="${LOGO_SRC}" alt="شعار معهد التأصيل العلمي" class="logo-img-footer">
        <div class="brand-name">معهد التأصيل العلمي</div>
        <p>برنامج علمي ميسر يُعين طالب العلم على بناء قوته العلمية والعملية</p>
      </div>
      <div class="footer-col">
        <h4>التواصل</h4>
        <a href="tel:${phone}"><span class="icon">📞</span><span>${phone}</span></a>
        <a href="mailto:${email}"><span class="icon">✉️</span><span>${email}</span></a>
        ${channelLinks}
      </div>

    </div>
    <div class="footer-bottom container">
      <p>© جميع الحقوق محفوظة لمعهد التأصيل العلمي</p>

    </div>
  </footer>`;
}

// ──────────────────────────────────────────────────
// SHARED INIT — called on every page
// ──────────────────────────────────────────────────
export function initSharedBehavior() {
  // Header scroll
  const header = document.getElementById('siteHeader');
  window.addEventListener('scroll', () => {
    header?.classList.toggle('scrolled', window.scrollY > 40);
  });

  // Hamburger — يفتح/يغلق القائمة المنسدلة ويحوّل الأيقونة إلى X
  const hamburger  = document.getElementById('hamburger');
  const mobileMenu = document.getElementById('mobileMenu');
  hamburger?.addEventListener('click', (e) => {
    e.stopPropagation();
    const isOpen = mobileMenu?.classList.toggle('open');
    hamburger.classList.toggle('open', isOpen);
  });

  // إغلاق القائمة عند الضغط خارجها
  document.addEventListener('click', e => {
    if (mobileMenu?.classList.contains('open')) {
      if (!mobileMenu.contains(e.target) && !hamburger?.contains(e.target)) {
        mobileMenu.classList.remove('open');
        hamburger?.classList.remove('open');
      }
    }
  });

  // إغلاق القائمة عند اختيار رابط داخلها
  mobileMenu?.querySelectorAll('a').forEach(a => {
    a.addEventListener('click', () => {
      mobileMenu.classList.remove('open');
      hamburger?.classList.remove('open');
    });
  });

  // Close dropdowns on outside click
  document.addEventListener('click', e => {
    const wrap = document.getElementById('userMenuWrap');
    if (wrap && !wrap.contains(e.target)) {
      const dropdown = document.getElementById('userDropdown');
      if (dropdown) dropdown.style.display = 'none';
    }
    const notifPanel = document.getElementById('notifPanel');
    const bell = document.getElementById('notifBell');
    if (notifPanel && !notifPanel.contains(e.target) && !(bell && bell.contains(e.target))) {
      notifPanel.style.display = 'none';
    }
  });

  // Scroll reveal
  const obs = new IntersectionObserver(entries => {
    entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add('visible'); obs.unobserve(e.target); } });
  }, { threshold: 0.08 });
  document.querySelectorAll('.reveal').forEach(el => obs.observe(el));
}

// ──────────────────────────────────────────────────
// GLOBAL FUNCTIONS (window)
// ──────────────────────────────────────────────────
window.toggleNotifPanel = function() {
  const p = document.getElementById('notifPanel');
  if (p) p.style.display = p.style.display === 'none' ? 'block' : 'none';
};

window.toggleUserMenu = function() {
  const d = document.getElementById('userDropdown');
  if (d) d.style.display = d.style.display === 'none' ? 'block' : 'none';
};

window.markAllRead = function() {};

window.handleHeaderLogout = async function() {
  try {
    const { getAuth, signOut } = await import('https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js');
    const { initializeApp, getApps } = await import('https://www.gstatic.com/firebasejs/10.7.1/firebase-app.js');
    const apps = getApps();
    if (apps.length) {
      const auth = getAuth(apps[0]);
      await signOut(auth);
    }
  } catch(e) {}
  window.location.href = 'index.html';
};

// Toast utility
export function showToast(msg, type = '') {
  let t = document.getElementById('globalToast');
  if (!t) { t = document.createElement('div'); t.id = 'globalToast'; t.className = 'toast'; document.body.appendChild(t); }
  t.textContent = msg;
  t.className = 'toast ' + type;
  setTimeout(() => t.classList.add('show'), 50);
  setTimeout(() => t.classList.remove('show'), 3200);
}
